import React, { useState } from "react";
import { useAuth } from "../context/AuthContext";
import { useNavigate } from "react-router-dom";
import axios from "axios";

export default function PostInternship() {
  const { currentUser } = useAuth();
  const navigate = useNavigate();

  const [form, setForm] = useState({
    title: "",
    company: "",
    location: "",
    duration: "",
    stipend: "",
    applyBy: "",
    description: "",
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const token = localStorage.getItem("token");
        // eslint-disable-next-line
      const response = await axios.post(
        "http://localhost:5000/api/internships",
        form,
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      );

      alert("Internship posted successfully!");
      navigate("/internship");
    } catch (err) {
      console.error(err);
      alert("Failed to post internship");
    }
  };

  if (currentUser?.role !== "admin" && currentUser?.role !== "hr") {
    return <p className="text-center p-4 text-red-500">Access Denied</p>;
  }

  return (
    <div className="max-w-xl mx-auto p-6 bg-white shadow-xl mt-10 rounded-xl">
      <h2 className="text-2xl font-bold mb-4 text-center text-green-700">Post Internship</h2>
      <form onSubmit={handleSubmit} className="space-y-4">
        {["title", "company", "location", "duration", "stipend", "applyBy"].map((field) => (
          <input
            key={field}
            type="text"
            name={field}
            placeholder={field.charAt(0).toUpperCase() + field.slice(1)}
            value={form[field]}
            onChange={handleChange}
            required
            className="w-full p-2 border border-gray-300 rounded-lg"
          />
        ))}
        <textarea
          name="description"
          placeholder="Description"
          value={form.description}
          onChange={handleChange}
          required
          className="w-full p-2 border border-gray-300 rounded-lg h-24"
        />
        <button
          type="submit"
          className="w-full bg-green-600 text-white py-2 px-4 rounded-lg hover:bg-green-700 transition"
        >
          Post Internship
        </button>
      </form>
    </div>
  );
}
